import React,
{
useEffect,
useState
}
from 'react';

import axios from 'axios';


const API_URL=
"http://localhost:5000/api";


function AdminDashboard(){

const[
users,
setUsers
]=useState([]);


const fetchPendingUsers=
async()=>{

try{

const res=
await axios.get(
`${API_URL}/admin/pending`
);

setUsers(
res.data
);

}

catch(error){

console.log(
error
);

}

};



const updateStatus=
async(id,status)=>{

await axios.put(

`${API_URL}/admin/approve/${id}`,

{
verificationStatus:status
}

);

fetchPendingUsers();

};



useEffect(()=>{

fetchPendingUsers();

},[]);



return(

<div style={{
padding:'40px'
}}>

<h1>
Admin Dashboard
</h1>

<h2>
Pending NGO & Volunteer Requests
</h2>


{users.length===0 && (

<p>
No pending requests
</p>

)}



{users.map((user)=>(

<div

key={user._id}

style={{
border:'1px solid #ddd',
padding:'20px',
marginTop:'20px',
borderRadius:'10px'
}}

>

<h3>
{user.name}
</h3>

<p>
{user.email}
</p>

<p>
Role:
{user.role}
</p>


<button

onClick={()=>
updateStatus(
user._id,
'Approved'
)
}

>

Approve

</button>


<button

onClick={()=>
updateStatus(
user._id,
'Rejected'
)
}

style={{
marginLeft:'10px'
}}

>

Reject

</button>


</div>

))}

</div>

);

}

export default AdminDashboard;
